from openai import AsyncOpenAI





async def main() -> None:
    base_url = "https://proxy.sharkielab.com/v1"
    api_key = "sk-Frj6Pu3OUfyOkPIz9Ji15awxikl8KcKVRZlEK702J2fcXFxA"
    model = "nai-diffusion-4-5-full-anlas-0"
    prompt = ("anime screencap aesthetic, painterly cel shade, rich color harmony, "
              "expressive brushstroke lines, depth-filled eye rendering, modern anime production art, "
              "polished commercial illustration, selfie photo, direct camera view, arm extended, "
              "phone out of frame, no phone visible, slight lens distortion, close up portrait, casual selfie angle, "
              "1girl, solo, young girl, petite build, slender, blue long hair, blue cat ears, animal ear fluff, "
              "white cat tail, soft delicate face, long eyelashes, beautiful detailed eyes, cute, masterpiece, best quality, "
              "energetic sparkling eyes with lively open-mouthed smile and raised playful brows, light blue oversized hoodie, "
              "white pleated miniskirt, cream-white over-the-knee socks, blue and white sneakers, thin silver necklace, "
              "small crossbody bag, sun-drenched cozy bedroom, cluttered desk with cute stationery, stacks of soft pillows and plush toys, "
              "pastel pink walls decorated with polaroids and fairy lights, warm morning sunlight through white lace curtains, blurred bookshelf, "
              "a few stray sketchbooks, cozy domestic atmosphere")
    width = 832
    height = 1216
    prompt_dict = {
        "prompt": prompt,
        "size": [width, height],
        "steps": 23
    }

    async with AsyncOpenAI(
            base_url=base_url,
            api_key=api_key
    ) as client:
        response = await client.chat.completions.create(
            model=model,
            messages=[
                {"role": "user", "content": json.dumps(prompt_dict)},
            ],
        )
        content = response.choices[0].message.content
        # 用正则提取所有图片
        images = re.findall(r'data:image/(\w+);base64,([A-Za-z0-9+/=]+)', content)
        for i, (fmt, b64) in enumerate(images):
            with open(f"output_{i}.{fmt}", "wb") as f:
                f.write(base64.b64decode(b64))
            print(f"保存: output_{i}.{fmt}")

